import json
import unittest


import dummy.jsonization as aas_jsonization


import tests.common
import tests.common_jsonization


class TestRoundTrips(unittest.TestCase):
    def test_abstract_item(self) -> None:
        for descendant_model_type in [
            'AnotherItem',
            'SomeItem'
        ]:
            for path in sorted(
                (
                    tests.common.TEST_DATA_DIR
                    / "Json"
                    / "Expected"
                    / descendant_model_type
                ).glob("**/*.json")
            ):
                with path.open("rt") as fid:
                    original_jsonable = json.load(fid)

                instance = aas_jsonization.abstract_item_from_jsonable(
                    original_jsonable
                )

                another_jsonable = aas_jsonization.to_jsonable(instance)

                mismatch = tests.common_jsonization.check_equal(
                    original_jsonable,
                    another_jsonable
                )

                self.assertListEqual([], list(map(str, mismatch)))


if __name__ == "__main__":
    unittest.main()


